dslRuleAfterChange:
/*!id: convert-try-finally-to-try-with-resources*/
/*!description: Convert a resource-closing try-finally block to a try-with-resources statement for AutoCloseable resources (Java 7+).*/
/*!severity: warning*/
/*!minJavaVersion: 8*/

$Type $resource = $resourceInitializer;
try {
    $statements$;
} finally {
    if ($resource != null) {
        $resource.close();
    }
}
=>
try ($Type $resource = $resourceInitializer) {
    $statements$;
}
;;

// A simpler pattern for a single resource without explicit null check in finally
$Type $resource = $resourceInitializer;
try {
    $statements$;
} finally {
    $resource.close();
}
=>
try ($Type $resource = $resourceInitializer) {
    $statements$;
}
;;

// A pattern for multiple resources (hypothetical multi-resource matching)
$Type1 $resource1 = $init1;
$Type2 $resource2 = $init2;
try {
    $statements$;
} finally {
    $resource1.close();
    $resource2.close();
}
=>
try ($Type1 $resource1 = $init1;
     $Type2 $resource2 = $init2) {
    $statements$;
}
;;

dslRule:
/*!id: jdt.internal.codecomplete.add-timeoutmonitor*/
/*!description: Add a CompletionTimeoutProgressMonitor to cu.codeComplete() calls for internal JDT content assist.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, api-evolution*/
org.eclipse.jdt.core.ICompilationUnit.$cu.codeComplete($offset, $requestor)
=> $cu.codeComplete($offset, $requestor, new org.eclipse.jdt.internal.ui.text.CompletionTimeoutProgressMonitor())
;;

org.eclipse.jdt.core.ICompilationUnit.$cu.codeComplete($offset, $requestor, $existingMonitor)
=> $cu.codeComplete($offset, $requestor, new org.eclipse.jdt.internal.ui.text.CompletionTimeoutProgressMonitor())
;;
